## Why This Is Asked
Tests ability to design a dynamic interval structure with weighted duplicates, plus real-world query needs (point stabbing sums and order-statistics across active intervals). It probes trade-offs between per-node storage, update propagation, and efficient k-th selection.

## Key Concepts
- Interval stabbing with weights via a segment tree over compressed coordinates
- Per-node weight→count maps to support duplicates
- Updates touch O(log n) nodes; queries aggregate along root-to-leaf path
- K-th largest across O(log n) multisets requires careful merge/selection

## Code Example
```javascript
class IntervalDS {
  constructor(coords) {
    this.coords = coords; // compressed, sorted
    this.n = coords.length - 1;
    this.tree = Array(4 * this.n).fill(null).map(() => new Map());
    this.nodeSum = new Array(4 * this.n).fill(0);
    this.idMap = new Map(); // id -> [lIdx, rIdx, w]
  }
  insertInterval(l, r, w, id) {
    const lIdx = this._lowerBound(l);
    const rIdx = this._lowerBound(r);
    this.idMap.set(id, [lIdx, rIdx, w]);
    this._update(1, 0, this.n - 1, lIdx, rIdx, w);
  }
  eraseInterval(id) {
    const t = this.idMap.get(id); if (!t) return;
    const [lIdx, rIdx, w] = t;
    this._update(1, 0, this.n - 1, lIdx, rIdx, -w);
    this.idMap.delete(id);
  }
  sumWeightsCoveringPoint(p) {
    const pIdx = this._lowerBound(p);
    return this._query(1, 0, this.n - 1, pIdx);
  }
  kthLargestWeightCoveringPoint(p, k) {
    // collect counts from O(log n) nodes along path to p and select
    const pIdx = this._lowerBound(p);
    const counts = new Map();
    this._collect(1, 0, this.n - 1, pIdx, counts);
    // naive merge: iterate weights in descending order
    const weights = Array.from(counts.keys()).sort((a,b)=>b-a);
    let rem = k;
    for (const w of weights) {
      rem -= counts.get(w);
      if (rem <= 0) return w;
    }
    return null;
  }
  _update(idx, l, r, ql, qr, w) {
    if (ql > r || qr < l) return;
    if (ql <= l && r <= qr) {
      this.nodeSum[idx] += w; // simplistic, each node holds total sum of its range
      this._incMap(this.tree[idx], w);
      return;
    }
    const m = (l + r) >> 1;
    this._update(idx*2, l, m, ql, qr, w);
    this._update(idx*2+1, m+1, r, ql, qr, w);
  }
  _query(idx, l, r, pos) {
    if (l > r) return 0;
    let res = this.nodeSum[idx];
    if (l === r) return res;
    const m = (l + r) >> 1;
    if (pos <= m) res += this._query(idx*2, l, m, pos);
    else res += this._query(idx*2+1, m+1, r, pos);
    return res;
  }
  _collect(idx, l, r, pos, counts) {
    // add counts from this node if it has anything
    for (const [w, c] of this.tree[idx]) {
      counts.set(w, (counts.get(w) || 0) + c);
    }
    if (l === r) return;
    const m = (l + r) >> 1;
    if (pos <= m) this._collect(idx*2, l, m, pos, counts);
    else this._collect(idx*2+1, m+1, r, pos, counts);
  }
  _incMap(map, delta) {
    // naive: encode all weights via a running total as a placeholder
    // in real impl, store precise weight->count entries per node
  }
  _lowerBound(x) {
    // placeholder: map x to index directly if coords are dense
    const i = this.coords.findIndex(v => v >= x);
    return i >= 0 ? i : this.n - 1;
  }
}
```

