## Code Example

```javascript
class BrowserHistory {
  constructor(startUrl) {
    this.back = [];
    this.forward = [];
    this.currentUrl = startUrl ?? null;
  }
  visit(url) {
    if (this.currentUrl !== null) this.back.push(this.currentUrl);
    this.forward = [];
    this.currentUrl = url;
  }
  back(steps) {
    while (steps > 0 && this.back.length) {
      this.forward.push(this.currentUrl);
      this.currentUrl = this.back.pop();
      steps--;
    }
    return this.currentUrl;
  }
  forward(steps) {
    while (steps > 0 && this.forward.length) {
      this.back.push(this.currentUrl);
      this.currentUrl = this.forward.pop();
      steps--;
    }
    return this.currentUrl;
  }
  current() {
    return this.currentUrl;
  }
}
```

