class Node { constructor(){ this.next = new Map(); this.end=0; this.sub=0; } }
class Trie { constructor(){ this.root=new Node(); }
  insertWord(w){ let cur=this.root; cur.sub++; for(const ch of w){ if(!cur.next.has(ch)) cur.next.set(ch,new Node()); cur=cur.next.get(ch); cur.sub++; } cur.end++; }
  eraseWord(w){ let cur=this.root; cur.sub--; for(const ch of w){ cur=cur.next.get(ch); cur.sub--; } cur.end--; }
  containsWord(w){ let cur=this.root; for(const ch of w){ if(!cur.next.has(ch)) return false; cur=cur.next.get(ch); } return cur.end>0; }
  countWithPrefix(pref){ let cur=this.root; for(const ch of pref){ if(!cur.next.has(ch)) return 0; cur=cur.next.get(ch); } return cur.sub; }
}
```

