## Why This Is Asked
Streaming data often requires maintaining a running statistic under insertions and deletions. The median is robust and a common interview target for dynamic data structures.

## Key Concepts
- Two-heap approach: keep lower half in a max-heap and upper half in a min-heap.
- Duplicates supported; lazy deletion via a delay map.
- Rebalancing invariant: size difference at most 1; median derived from heap tops.

## Code Example
```javascript
class MedianDS {
  constructor(){
    this.lo = new MaxHeap(); // lower half
    this.hi = new MinHeap(); // upper half
    this.delayed = new Map();
    this.sizeLo = 0;
    this.sizeHi = 0;
  }
  _cleanTop(h) {
    const top = h.peek();
    while (top !== null && this.delayed.get(top) > 0) {
      h.pop();
      this.delayed.set(top, this.delayed.get(top) - 1);
    }
  }
  add(x){
    if (this.sizeLo === 0 || x <= this.lo.peek()) {
      this.lo.push(x); this.sizeLo++;
    } else { this.hi.push(x); this.sizeHi++; }
    this._balance();
  }
  remove(x){
    const loTop = this.lo.peek();
    if (loTop !== null && x <= loTop) {
      this.delayed.set(x, (this.delayed.get(x) || 0) + 1);
      this.sizeLo--;
      if (x === loTop) this._cleanTop(this.lo);
    } else {
      this.delayed.set(x, (this.delayed.get(x) || 0) + 1);
      this.sizeHi--;
      this._cleanTop(this.hi);
    }
    this._balance();
  }
  _balance(){
    if (this.sizeLo > this.sizeHi + 1) {
      this.hi.push(this.lo.pop()); this.sizeLo--; this.sizeHi++;
    } else if (this.sizeHi > this.sizeLo) {
      this.lo.push(this.hi.pop()); this.sizeHi--; this.sizeLo++;
    }
    this._cleanTop(this.lo); this._cleanTop(this.hi);
  }
  getMedian(){
    if (this.sizeLo === 0) return null;
    if (this.sizeLo > this.sizeHi) return this.lo.peek();
    return (this.lo.peek() + this.hi.peek()) / 2;
  }
}
```

