## Why This Is Asked

This question evaluates practical knowledge of order-statistics trees for managing dynamic value sets with range queries and per-ID updates—a common pattern in analytics, billing, and HR systems.

## Key Concepts

- Augmented BST (order-statistics tree) with duplicate support via frequency counts
- Range-sum and range-count queries using subtree aggregation
- Hash map for O(1) ID-to-salary lookups, enabling efficient updates and deletions
- Amortized O(log n) operations through balanced tree structure

## Code Example

```javascript
class SalaryTree {
  constructor() {
    this.root = null;
    this.idToSalary = new Map();
  }

  addEmployee(id, salary) {
    this.idToSalary.set(id, salary);
    this.root = this._insert(this.root, salary);
  }

  removeEmployee(id) {
    const salary = this.idToSalary.get(id);
    if (salary === undefined) return;
    this.idToSalary.delete(id);
    this.root = this._remove(this.root, salary);
  }

  updateSalary(id, newSalary) {
    this.removeEmployee(id);
    this.addEmployee(id, newSalary);
  }

  countSalariesInRange(min, max) {
    return this._countRange(this.root, min, max);
  }

  sumSalariesInRange(min, max) {
    return this._sumRange(this.root, min, max);
  }

  kthSalaryInRange(min, max, k) {
    return this._kthRange(this.root, min, max, k);
  }

  _insert(node, salary) {
    if (!node) return new Node(salary);
    if (salary === node.salary) {
      node.freq++;
    } else if (salary < node.salary) {
      node.left = this._insert(node.left, salary);
    } else {
      node.right = this._insert(node.right, salary);
    }
    return this._rebalance(node);
  }

  _remove(node, salary) {
    if (!node) return null;
    if (salary === node.salary) {
      if (node.freq > 1) {
        node.freq--;
        return node;
      }
      return this._merge(node.left, node.right);
    }
    if (salary < node.salary) {
      node.left = this._remove(node.left, salary);
    } else {
      node.right = this._remove(node.right, salary);
    }
    return this._rebalance(node);
  }

  _rebalance(node) {
    this._update(node);
    return node;
  }

  _update(node) {
    node.subtreeSize = node.freq;
    node.subtreeSum = node.salary * node.freq;
    if (node.left) {
      node.subtreeSize += node.left.subtreeSize;
      node.subtreeSum += node.left.subtreeSum;
    }
    if (node.right) {
      node.subtreeSize += node.right.subtreeSize;
      node.subtreeSum += node.right.subtreeSum;
    }
  }

  _merge(left, right) {
    if (!left || !right) return left || right;
    if (left.pri < right.pri) {
      left.right = this._merge(left.right, right);
      this._update(left);
      return left;
    }
    right.left = this._merge(left, right.left);
    this._update(right);
    return right;
  }

  _countRange(node, min, max) {
    if (!node) return 0;
    if (node.salary < min) return this._countRange(node.right, min, max);
    if (node.salary > max) return this._countRange(node.left, min, max);
    const leftCount = node.left ? node.left.subtreeSize : 0;
    const rightCount = node.right ? node.right.subtreeSize : 0;
    return leftCount + node.freq + rightCount;
  }

  _sumRange(node, min, max) {
    if (!node) return 0;
    if (node.salary < min) return this._sumRange(node.right, min, max);
    if (node.salary > max) return this._sumRange(node.left, min, max);
    const leftSum = node.left ? node.left.subtreeSum : 0;
    const rightSum = node.right ? node.right.subtreeSum : 0;
    return leftSum + (node.salary * node.freq) + rightSum;
  }

  _kthRange(node, min, max, k) {
    if (!node) return null;
    if (node.salary < min) return this._kthRange(node.right, min, max, k);
    if (node.salary > max) return this._kthRange(node.left, min, max, k);
    const leftSize = node.left ? node.left.subtreeSize : 0;
    if (k < leftSize) return this._kthRange(node.left, min, max, k);
    if (k < leftSize + node.freq) return node.salary;
    const rightK = k - leftSize - node.freq;
    return this._kthRange(node.right, min, max, rightK);
  }
}

class Node {
  constructor(salary) {
    this.salary = salary;
