```javascript
class TrieNode {
  constructor() {
    this.children = new Map();
    this.weightMultiset = new Map();
    this.subtreeTotal = 0;
  }
}

class DynamicPrefixDictionary {
  constructor() {
    this.root = new TrieNode();
  }

  insertWord(word, weight) {
    let node = this.root;
    for (const char of word) {
      if (!node.children.has(char)) {
        node.children.set(char, new TrieNode());
      }
      node = node.children.get(char);
      node.weightMultiset.set(weight, (node.weightMultiset.get(weight) || 0) + 1);
      node.subtreeTotal += weight;
    }
  }

  eraseWord(word, weight) {
    let node = this.root;
    const path = [];
    for (const char of word) {
      if (!node.children.has(char)) return false;
      node = node.children.get(char);
      path.push(node);
    }
    const count = node.weightMultiset.get(weight);
    if (!count || count <= 0) return false;
    if (count === 1) {
      node.weightMultiset.delete(weight);
    } else {
      node.weightMultiset.set(weight, count - 1);
    }
    node.subtreeTotal -= weight;
    return true;
  }

  sumWeightsWithPrefix(prefix) {
    let node = this.root;
    for (const char of prefix) {
      if (!node.children.has(char)) return 0;
      node = node.children.get(char);
    }
    return node.subtreeTotal;
  }

  kthLargestWeightWithPrefix(prefix, k) {
    let node = this.root;
    for (const char of prefix) {
      if (!node.children.has(char)) return null;
      node = node.children.get(char);
    }
    if (k <= 0 || k > this.getTotalCount(node.weightMultiset)) return null;
    const sortedWeights = [...node.weightMultiset.entries()]
      .sort((a, b) => b[0] - a[0]);
    let remaining = k;
    for (const [weight, count] of sortedWeights) {
      remaining -= count;
      if (remaining <= 0) return weight;
    }
    return null;
  }

  getTotalCount(multiset) {
    let total = 0;
    for (const count of multiset.values()) total += count;
    return total;
  }
}
```

