function kth(node, k) {
  if (!node) return null;
  const leftSize = node.l?.sz || 0;
  if (k <= leftSize) return kth(node.l, k);
  if (k <= leftSize + node.c) return node.v;
  return kth(node.r, k - leftSize - node.c);
