## Key Concepts
- **Two heaps for median maintenance**: A max-heap stores the lower half, while a min-heap stores the upper half, allowing O(1) median retrieval
- **Duplicate handling**: Store actual values in heaps with a frequency counter map to track occurrences
- **Lazy deletion**: Defer removals by updating a delayed-delete map; prune elements lazily when they surface at heap tops to achieve O(log n) amortized erase

## Code Example
```python
import heapq

class DualHeap:
    def __init__(self):
        self.small = []  # max-heap (store negatives)
        self.large = []  # min-heap
        self.delayed = {}  # lazy deletion map
        self.small_size = 0
        self.large_size = 0

    def prune(self, heap):
        while heap:
            num = -heap[0] if heap is self.small else heap[0]
            if self.delayed.get(num, 0) > 0:
                heapq.heappop(heap)
                self.delayed[num] -= 1
                if self.delayed[num] == 0:
                    del self.delayed[num]
            else:
                break

    def rebalance(self):
        if self.small_size > self.large_size + 1:
            val = -heapq.heappop(self.small)
            self.small_size -= 1
            heapq.heappush(self.large, val)
            self.large_size += 1
        elif self.large_size > self.small_size + 1:
            val = heapq.heappop(self.large)
            self.large_size -= 1
            heapq.heappush(self.small, -val)
            self.small_size += 1

    def insert(self, num):
        if not self.small or num <= -self.small[0]:
            heapq.heappush(self.small, -num)
            self.small_size += 1
        else:
            heapq.heappush(self.large, num)
            self.large_size += 1
        self.rebalance()

    def erase(self, num):
        self.delayed[num] = self.delayed.get(num, 0) + 1
        if num <= -self.small[0]:
            self.small_size -= 1
        else:
            self.large_size -= 1
        self.rebalance()

    def getMedian(self):
        if self.small_size > self.large_size:
            self.prune(self.small)
            return -self.small[0]
        elif self.large_size > self.small_size:
            self.prune(self.large)
            return self.large[0]
        return (-self.small[0] + self.large[0]) / 2
```

