questions.answer:
Use a combination of three data structures:

1. **Hash Map** (id → SessionNode): O(1) access to update scores and check session existence.

2. **Order-Statistics Tree** (augmented BST, ordered by score DESC, then id ASC): Enables O(log n) insertion, deletion, and rank-based queries. Each node stores `subtreeSize` (count of all nodes in subtree) to support order-statistics.

3. **Queue** (sorted by lastActive timestamp): Sessions enqueued on insert. Expiration dequeues from front.

```python
import random
from dataclasses import dataclass
from typing import Optional, Dict, List, Tuple

@dataclass
class Session:
    id: str
    score: float
    lastActive: int

class OSTNode:
    def __init__(self, session: Session):
        self.session = session
        self.score = session.score
        self.id = session.id
        self.priority = random.random()
        self.left: Optional[OSTNode] = None
        self.right: Optional[OSTNode] = None
        self.subtreeSize = 1

    def _update(self):
        self.subtreeSize = 1
        if self.left:
            self.subtreeSize += self.left.subtreeSize
        if self.right:
            self.subtreeSize += self.right.subtreeSize

class Treap:
    def __init__(self):
        self.root: Optional[OSTNode] = None

    def _rotate_right(self, y: OSTNode) -> OSTNode:
        x = y.left
        y.left = x.right
        x.right = y
        y._update()
        x._update()
        return x

    def _rotate_left(self, x: OSTNode) -> OSTNode:
        y = x.right
        x.right = y.left
        y.left = x
        x._update()
        y._update()
        return y

    def insert(self, node: OSTNode, new_node: OSTNode) -> OSTNode:
        if not node:
            return new_node

        # Order: score DESC, then id ASC
        if (new_node.score, new_node.id) > (node.score, node.id):
            node.left = self.insert(node.left, new_node)
            if node.left.priority < node.priority:
                node = self._rotate_right(node)
        else:
            node.right = self.insert(node.right, new_node)
            if node.right.priority < node.priority:
                node = self._rotate_left(node)

        node._update()
        return node

    def erase(self, node: OSTNode, score: float, id: str) -> OSTNode:
        if not node:
            return None

        if (score, id) == (node.score, node.id):
            if not node.left:
                return node.right
            if not node.right:
                return node.left
            if node.left.priority < node.right.priority:
                node = self._rotate_right(node)
                node.right = self.erase(node.right, score, id)
            else:
                node = self._rotate_left(node)
                node.left = self.erase(node.left, score, id)
        elif (score, id) > (node.score, node.id):
            node.left = self.erase(node.left, score, id)
        else:
            node.right = self.erase(node.right, score, id)

        node._update()
        return node

    def kth_largest(self, node: OSTNode, k: int) -> Optional[OSTNode]:
        if not node or k <= 0:
            return None

        left_size = node.left.subtreeSize if node.left else 0

        if k <= left_size:
            return self.kth_largest(node.left, k)
        elif k == left_size + 1:
            return node
        else:
            return self.kth_largest(node.right, k - left_size - 1)

    def get_median(self, node: OSTNode) -> Optional[float]:
        if not node:
            return None

        size = node.subtreeSize
        mid = (size + 1) // 2
        left_size = node.left.subtreeSize if node.left else 0

        if mid <= left_size:
            return self.get_median(node.left)
        elif mid == left_size + 1:
            return node.score
        else:
            return self.get_median(node.right)

class SessionTracker:
    def __init__(self):
        self.sessions: Dict[str, Session] = {}
        self.queue: List[Tuple[int, str]] = []  # (timestamp, id)
        self.tree = Treap()

    def _expire_sessions_before(self, ts: int) -> None:
        while self.queue and self.queue[0][0] < ts:
            _, sid = self.queue.pop(0)
            if sid in self.sessions:
                session = self.sessions.pop(sid)
                self.tree.erase(self.tree.root, session.score, sid)

    def insertSession(self, id: str, score: float, ts: int) -> None:
        if id in self.sessions:
            self.updateScore(id, score - self.sessions[id].score)
            self.sessions[id].lastActive = ts
            return

        session = Session(id, score, ts)
        self.sessions[id] = session
        self.queue.append((ts, id))
        self.tree.root = self.tree.insert(self.tree.root, OSTNode(session))

    def updateScore(self, id: str, delta: float) -> None:
        if id not in self.sessions:
            return

        old_session = self.sessions[id]
        old_score = old_session.score
        old_session.score += delta
        new_score = old_session.score

        self.tree.root = self.tree.erase(self.tree.root, old_score, id)
        self.tree.root = self.tree.insert(self.tree.root, OSTNode(old_session))

    def expireSessionsBefore(self, ts: int) -> None:
        self._expire_sessions_before(ts)

    def topK(self, window: int, k: int) -> List[Tuple[str, float]]:
        now = self._get_current_time()
        self._expire_sessions_before(now - window)

        results = []
        for i in range(1, k + 1):
            node = self.tree.kth_largest(self.tree.root, i)
            if not node:
                break
            results.append((node.id, node.score))

        return results

    def medianScore(self, window: int) -> Optional[float]:
        now = self._get_current_time()
        self._expire_sessions_before(now - window)
        return self.tree.get_median(self.tree.root)

    def _get_current_time(self) -> int:
        import time
        return int(time.time())
```

**Complexities:**
- `insertSession`: O(log n) - hash lookup + BST insert
- `updateScore`: O(log n) - erase + insert in treap
- `expireSessionsBefore`: Amortized O(1) per session - each session removed once
- `topK`: O(k log n) - k successive kth-largest queries
- `medianScore`: O(log n) - single order-statistics traversal

**Order-Statistics Tree Details:**
The augmented BST tracks `subtreeSize` at each node. For median: compute rank = (size+1)//2, then traverse tree comparing rank to left subtree size. For topK: repeatedly find kth-largest, removing after each fetch (or use in-order of reversed tree).

