class HistogramQuantile {
  constructor(){
    this.N = 2001;
    this.ft = new Array(this.N+1).fill(0);
  }
  update(i, delta){
    for (let x = i; x <= this.N; x += x & -x) this.ft[x] += delta;
  }
  insertValue(v){ this.update(v + 1001, 1); }
  eraseValue(v){ this.update(v + 1001, -1); }
  sum(i){ let s = 0; for (let x = i; x > 0; x -= x & -x) s += this.ft[x]; return s; }
  lowerBound(k){
    let idx = 0, bit = 1 << 11; // > 2001
    let acc = 0;
    for (; bit; bit >>= 1){
      const next = idx + bit;
      if (next <= this.N && acc + this.ft[next] < k){ idx = next; acc += this.ft[next]; }
    }
    return idx + 1;
  }
  findQuantile(p){
    const total = this.sum(this.N);
    if (total === 0) return null;
    const k = Math.ceil(p * total);
    const i = this.lowerBound(k);
    return i - 1001;
  }
}
