## Code Example
```javascript
class IntervalDS {
  constructor(coords) {
    this.coords = coords;
    this.N = coords.length;
    this.tree = Array(4 * this.N).fill(null).map(() => new Map());
    this.sums = Array(4 * this.N).fill(0);
  }

  insert(l, r, w) {
    this.update(1, 0, this.N - 1, l, r, w, 1);
  }

  erase(l, r, w) {
    this.update(1, 0, this.N - 1, l, r, w, -1);
  }

  update(node, start, end, l, r, w, delta) {
    if (r < start || end < l) return;
    if (l <= start && end <= r) {
      const count = this.tree[node].get(w) || 0;
      this.tree[node].set(w, count + delta);
      if (this.tree[node].get(w) === 0) this.tree[node].delete(w);
      this.sums[node] += w * delta;
      return;
    }
    const mid = Math.floor((start + end) / 2);
    this.update(node * 2, start, mid, l, r, w, delta);
    this.update(node * 2 + 1, mid + 1, end, l, r, w, delta);
    this.sums[node] = this.sums[node * 2] + this.sums[node * 2 + 1];
  }

  sumAtPoint(x) {
    return this.querySum(1, 0, this.N - 1, x);
  }

  querySum(node, start, end, x) {
    if (x < start || x > end) return 0;
    if (start === end) return this.sums[node];
    const mid = Math.floor((start + end) / 2);
    return this.sums[node] + 
      (x <= mid ? this.querySum(node * 2, start, mid, x) 
                : this.querySum(node * 2 + 1, mid + 1, end, x));
  }

  kthLargest(x, k) {
    const weights = [...new Set(this.getWeightsAtPoint(x))].sort((a, b) => b - a);
    if (k > weights.length) return null;
    return weights[k - 1];
  }

  getWeightsAtPoint(x) {
    const result = [];
    this.collectWeights(1, 0, this.N - 1, x, result);
    return result;
  }

  collectWeights(node, start, end, x, result) {
    if (x < start || x > end) return;
    for (const [w, count] of this.tree[node]) {
      result.push(...Array(count).fill(w));
    }
    if (start === end) return;
    const mid = Math.floor((start + end) / 2);
    this.collectWeights(node * 2, start, mid, x, result);
    this.collectWeights(node * 2 + 1, mid + 1, end, x, result);
  }
}
```

