Insert(7):        [3][5] cnt=1   cnt=2   cnt=1
rank(5): 1        (only 3 < 5)
select(2): 5      (3 is 1st, 5 is 2nd)
select(3): 5      (both 5s count)
Erase(5):         [5] cnt=1
