class Node {
  constructor(ch) {
    this.c = ch;
    this.pr = Math.random();
    this.left = null; this.right = null;
    this.sz = 1;
    this.h1 = ch.charCodeAt(0);
    this.h2 = ch.charCodeAt(0);
  }
}
// Update size and hashes from children
function upd(n){ if(!n) return; n.sz = 1; n.h1 = n.c.charCodeAt(0); n.h2 = n.c.charCodeAt(0);
  if(n.left){ n.sz += n.left.sz; n.h1 = n.left.h1 + somePow1; n.h2 = n.left.h2 + somePow2; }
  if(n.right){ n.sz += n.right.sz; n.h1 = n.h1 + rightHash1; n.h2 = n.h2 + rightHash2; }
}
function split(t, k){ // split first k chars to a
  if(!t) return [null, null];
  if(size(t.left) >= k){ const [l, r] = split(t.left, k); t.left = r; upd(t); return [l, t]; }
  const [l, r] = split(t.right, k - size(t.left) - 1); t.right = l; upd(t); return [t, r];
}
function merge(a, b){ if(!a||!b) return a||b; if(a.pr < b.pr){ a.right = merge(a.right, b); upd(a); return a; } else { b.left = merge(a, b.left); upd(b); return b; } }
```

