## Why This Is Asked
Maintaining the median under dynamic inserts and deletes is a common, practical data-structure task that tests understanding of balanced structures and handling edge cases with duplicates.

## Key Concepts
- Median of a dynamic multiset
- Heaps: max-heap for lower half, min-heap for upper half
- Lazy deletion via hashmap to avoid O(n) removal
- Balancing logic and handling duplicates with reference counting

## Code Example
```javascript
class MedianSet {
  constructor() {
    this.low = new MaxHeap();
    this.high = new MinHeap();
    this.delLow = new Map();
    this.delHigh = new Map();
  }

  _prune() {
    while (this.low.size() > 0 && this.delLow.has(this.low.peek())) {
      const count = this.delLow.get(this.low.peek()) - 1;
      if (count <= 0) this.delLow.delete(this.low.peek());
      else this.delLow.set(this.low.peek(), count);
      this.low.pop();
    }
    while (this.high.size() > 0 && this.delHigh.has(this.high.peek())) {
      const count = this.delHigh.get(this.high.peek()) - 1;
      if (count <= 0) this.delHigh.delete(this.high.peek());
      else this.delHigh.set(this.high.peek(), count);
      this.high.pop();
    }
  }

  _rebalance() {
    if (this.low.size() > this.high.size() + 1) {
      this.high.push(this.low.pop());
    } else if (this.high.size() > this.low.size() + 1) {
      this.low.push(this.high.pop());
    }
  }

  insertScore(x) {
    if (this.low.size() === 0 || x <= this.low.peek()) {
      this.low.push(x);
    } else {
      this.high.push(x);
    }
    this._rebalance();
  }

  removeScore(x) {
    if (this.low.size() > 0 && x <= this.low.peek()) {
      const count = this.delLow.get(x) || 0;
      this.delLow.set(x, count + 1);
    } else {
      const count = this.delHigh.get(x) || 0;
      this.delHigh.set(x, count + 1);
    }
    this._prune();
    this._rebalance();
  }

  getMedian() {
    this._prune();
    if (this.low.size() > this.high.size()) return this.low.peek();
    if (this.high.size() > this.low.size()) return this.high.peek();
    return (this.low.peek() + this.high.peek()) / 2;
  }
}
```

