- Handling time-evolving duplicates safely

## Code Example
```javascript
class LeaderboardTreap {
  constructor() { this.root = null; }
  _cmp(a, b) {
    if (a.score !== b.score) return a.score - b.score;
    return a.playerId.localeCompare(b.playerId);
  }
  _size(n) { return n ? n.size : 0; }
  _update(n) { if (n) n.size = 1 + this._size(n.left) + this._size(n.right); }
  _rotateLeft(p) {
    const r = p.right; p.right = r.left; r.left = p; this._update(p); this._update(r); return r;
  }
  _rotateRight(p) {
    const l = p.left; p.left = l.right; l.right = p; this._update(p); this._update(l); return l;
  }
  insertScore(playerId, score) {
    const key = { playerId, score, __prio: Math.random() };
    this.root = this._insert(this.root, key);
  }
  _insert(n, key) {
    if (!n) return { key, priority: key.__prio, left: null, right: null, size: 1 };
    if (this._cmp(key, n.key) < 0) {
      n.left = this._insert(n.left, key);
      if (n.left.priority > n.priority) n = this._rotateRight(n);
    } else {
      n.right = this._insert(n.right, key);
      if (n.right.priority > n.priority) n = this._rotateLeft(n);
    }
    this._update(n); return n;
  }
  eraseScore(playerId, score) {
    const key = { playerId, score };
    this.root = this._erase(this.root, key);
  }
  _erase(n, key) {
    if (!n) return null;
    const c = this._cmp(key, n.key);
    if (c < 0) { n.left = this._erase(n.left, key); }
    else if (c > 0) { n.right = this._erase(n.right, key); }
    else {
      if (!n.left) return n.right;
      if (!n.right) return n.left;
      if (n.left.priority > n.right.priority) { n = this._rotateRight(n); n.right = this._erase(n.right, key); }
      else { n = this._rotateLeft(n); n.left = this._erase(n.left, key); }
    }
    this._update(n); return n;
  }
  getRank(score) {
    const dfs = (n) => {
      if (!n) return 0;
      if (n.key.score <= score) return this._size(n.left) + 1 + dfs(n.right);
      return dfs(n.left);
    };
    return dfs(this.root);
  }
}
```

