## Why This Is Asked
Interviews reward solid understanding of maintaining order statistics with dynamic updates. Median is a practical metric in streaming data and finance workloads.

## Key Concepts
- Median maintenance with two heaps: max-heap for lower half, min-heap for upper half
- Invariant: all low <= all high; size difference <= 1
- Duplicates handled naturally; erase uses lazy deletion via a hashmap
- Pruning tops when they’re marked as deleted

## Code Example
```javascript
class MedianMultiset {
  constructor() {
    this.low = new MaxHeap(); // max-heap
    this.high = new MinHeap(); // min-heap
    this.delayed = new Map(); // value -> count to delete lazily
    this.size = 0; // total elements including delayed
  }
  _prune(heap) {
    while (heap.top !== undefined && this.delayed.get(heap.top)) {
      const v = heap.pop();
      this.delayed.set(v, this.delayed.get(v) - 1);
    }
  }
  insert(x) {
    if (this.low.isEmpty() || x <= this.low.top) this.low.push(x);
    else this.high.push(x);
    this.size++;
    this._rebalance();
  }
  erase(x) {
    if (x <= this.low.top) {
      this._mark(x);
    } else {
      this._mark(x);
    }
    this.size--;
    this._rebalance();
  }
  _mark(x){
    this.delayed.set(x, (this.delayed.get(x) || 0) + 1);
  }
  _rebalance() {
    // prune tops first if needed
    this._prune(this.low); this._prune(this.high);
    // move elements to maintain size balance
    while (this.low.size() > this.high.size() + 1) {
      this.high.push(this.low.pop());
      this._prune(this.low); this._prune(this.high);
    }
    while (this.high.size() > this.low.size()) {
      this.low.push(this.high.pop());
      this._prune(this.low); this._prune(this.high);
    }
  }
  getMedian() {
    if (this.size === 0) return null;
    this._prune(this.low);
    if (this.low.size() > this.high.size()) return this.low.top;
    return Math.min(this.low.top, this.high.top);
  }
}
// Simple heap placeholders; production would implement full heap APIs
class MaxHeap {
  constructor(){ this._a=[]; }
  push(x){ this._a.push(x); this._siftUp(this._a.length-1); }
  pop(){ if(this._a.length===0) return undefined; const v=this._a[0]; const end=this._a.pop(); if(this._a.length){ this._a[0]=end; this._siftDown(0);} return v; }
  get top(){ return this._a[0]; }
  isEmpty(){ return this._a.length===0; }
  size(){ return this._a.length; }
  _siftUp(i){ const a=this._a; while(i>0){ const p=(i-1)>>1; if(a[p]>=a[i]) break; [a[p],a[i]]=[a[i],a[p]]; i=p; } }
  _siftDown(i){ const a=this._a; const n=a.length; while(true){ let l=i*2+1, r=l+1, largest=i; if(l<n && a[l]>a[largest]) largest=l; if(r<n && a[r]>a[largest]) largest=r; if(largest===i) break; [a[i],a[largest]]=[a[largest],a[i]]; i=largest; } }
}
class MinHeap {
  constructor(){ this._a=[]; }
  push(x){ this._a.push(x); this._siftUp(this._a.length-1); }
  pop(){ if(this._a.length===0) return undefined; const v=this._a[0]; const end=this._a.pop(); if(this._a.length){ this._a[0]=end; this._siftDown(0);} return v; }
  get top(){ return this._a[0]; }
  isEmpty(){ return this._a.length===0; }
  size(){ return this._a.length; }
  _siftUp(i){ const a=this._a; while(i>0){ const p=(i-1)>>1; if(a[p]<=a[i]) break; [a[p],a[i]]=[a[i],a[p]]; i=p; } }
  _siftDown(i){ const a=this._a; const n=a.length; while(true){ let l=i*2+1, r=l+1, smallest=i; if(l<n && a[l]<a[smallest]) smallest=l; if(r<n && a[r]<a[smallest]) smallest=r; if(smallest===i) break; [a[i],a[smallest]]=[a[smallest],a[i]]; i=smallest; } }
}
