## Why This Is Asked

This question tests mastery of rope-like data structures for dynamic sequences with cut-paste operations while maintaining fast range queries.

## Key Concepts

- **Implicit treap / rope**: Uses position as the key rather than explicit values
- **Split and merge operations**: Fundamental primitives for manipulating segments
- **Augmented data**: size and range sum maintained at each node
- **Edge cases**: Properly handling when dest overlaps with [l, r]

## Code Example

```javascript
class Node {
  constructor(v) {
    this.v = v;
    this.pr = Math.random();
    this.l = this.r = null;
    this.sz = 1;
    this.sum = v;
  }
}

function upd(t) {
  if (!t) return;
  t.sz = 1 + sz(t.l) + sz(t.r);
  t.sum = t.v + sum(t.l) + sum(t.r);
}

function split(t, k, l, r) {
  if (!t) return [null, null];
  if (sz(t.l) >= k) {
    let [a, b] = split(t.l, k, l, r);
    t.l = b; upd(t);
    return [a, t];
  } else {
    let [a, b] = split(t.r, k - sz(t.l) - 1, l, r);
    t.r = a; upd(t);
    return [t, b];
  }
}

function merge(a, b) {
  if (!a || !b) return a || b;
  if (a.pr < b.pr) {
    a.r = merge(a.r, b); upd(a); return a;
  } else {
    b.l = merge(a, b.l); upd(b); return b;
  }
}

function rangeSum(t, l, r) {
  let [a, bc] = split(t, l);
  let [b, c] = split(bc, r - l + 1);
  let res = sum(b);
  t = merge(a, merge(b, c));
  return res;
}

function moveSegment(t, l, r, dest) {
  let len = r - l + 1;
  let [a, bc] = split(t, l);
  let [b, c] = split(bc, len);
  t = merge(a, c);

  let pos = dest <= l ? dest : dest - len;
  let [x, y] = split(t, pos);\n  return merge(merge(x, b), y);
}
```

questions.answer:
Design a time-windowed dynamic multiset supporting the following operations:
- insertEvent(id, t, v): Insert an event with given id, timestamp t, and value v
- deleteEvent(id): Remove an event by its id
- sumInWindow(t, W): Return the sum of all values in the time window [t-W+1, t]
- kthLargestInWindow(t, W, k): Return the k-th largest value in the window

Duplicates are allowed. The implementation uses:
- A deque to maintain events in insertion order
- A running sum for O(1) sumInWindow queries
- An order-statistics BST (mapping value → count) to support kthLargest in O(log n)

Expired events are automatically removed as the window slides forward, ensuring O(log n) updates per insert/delete.

```javascript
class WindowMultiset {
  constructor(windowSize) {
    this.W = windowSize;
    this.events = new Map(); // id → {t, v}
    this.deque = [];
    this.valueCounts = new Map(); // value → count
    this.runningSum = 0;
  }

  expire(t) {
    const threshold = t - this.W + 1;
    while (this.deque.length > 0 && this.deque[0].t < threshold) {
      const evt = this.deque.shift();
      this.runningSum -= evt.v;
      const count = this.valueCounts.get(evt.v) - 1;
      if (count === 0) this.valueCounts.delete(evt.v);
      else this.valueCounts.set(evt.v, count);
      this.events.delete(evt.id);
    }
  }

  insertEvent(id, t, v) {
    this.expire(t);
    if (this.events.has(id)) this.deleteEvent(id);
    this.events.set(id, {t, v});
    this.deque.push({id, t, v});
    this.runningSum += v;
    this.valueCounts.set(v, (this.valueCounts.get(v) || 0) + 1);
  }

  deleteEvent(id) {
    const evt = this.events.get(id);
    if (!evt) return;
    this.runningSum -= evt.v;
    const count = this.valueCounts.get(evt.v) - 1;
    if (count === 0) this.valueCounts.delete(evt.v);
    else this.valueCounts.set(evt.v, count);
    this.events.delete(id);
  }

  sumInWindow(t, W) {
    this.expire(t);
    return this.runningSum;
  }

  kthLargestInWindow(t, W, k) {
    this.expire(t);
    const sorted = [...this.valueCounts.entries()].sort((a, b) => b[0] - a[0]);
    let remaining = k;
    for (const [value, count] of sorted) {
      remaining -= count;
      if (remaining <= 0) return value;
    }
    return null;
  }
}
```

