class SlidingWindow {
  constructor(w){
    this.w = w;
    this.q = []; // {val, idx}
    this.min = []; // {val, idx}
    this.sum = 0;
    this.i = 0;
  }
  add(v){
    const idx = this.i++;
    this.q.push({val:v, idx});
    this.sum += v;
    while (this.min.length && this.min[this.min.length-1].val >= v) this.min.pop();
    this.min.push({val:v, idx});
    if (this.q.length > this.w){
      const old = this.q.shift();
      this.sum -= old.val;
      if (this.min[0].idx === old.idx) this.min.shift();
    }
  }
  getMin(){ return this.min[0]?.val; }
  getSum(){ return this.sum; }
