class Node {
  constructor(){
    this.next = new Map();
    this.subtreeSum = 0;
    this.weights = new Map(); // weight -> count
  }
}

function addToMultiset(ms, w, delta){
  ms.set(w, (ms.get(w) || 0) + delta);
  if (ms.get(w) <= 0) ms.delete(w);
}

function insert(root, s, w){
  let cur = root;
  addToMultiset(cur.weights, w, 1);
  cur.subtreeSum += w;
  for (let ch of s){
    if (!cur.next.has(ch)) cur.next.set(ch, new Node());
    cur = cur.next.get(ch);
    addToMultiset(cur.weights, w, 1);
    cur.subtreeSum += w;
  }
}

function erase(root, s, w){
  let cur = root;
  addToMultiset(cur.weights, w, -1);
  cur.subtreeSum -= w;
  for (let ch of s){
    cur = cur.next.get(ch);
    addToMultiset(cur.weights, w, -1);
    cur.subtreeSum -= w;
  }
}
