// Pseudo-implementation sketch for insertInterval/eraseInterval
class IntervalIndex {
  constructor(points) {
    this.tree = new SegmentTree(points.length - 1);
  }

  insertInterval(l, r, w, id) {
    const range = this.getCompressedRange(l, r);
    this.tree.update(range.l, range.r, (node) => {
      node.multiset.add({ weight: w, id });
      node.sum += w;
    });
  }

  eraseInterval(id, w) {
    // Find all intervals containing this id and remove one instance
    this.tree.queryById(id, (node) => {
      node.multiset.delete({ weight: w, id });
      node.sum -= w;
    });
  }

  sumWeightsCoveringPoint(p) {
    const idx = this.compress(p);
    return this.tree.queryPoint(idx, (node) => node.sum);
  }

  kthLargestWeightCoveringPoint(p, k) {
    const idx = this.compress(p);
    const weights = this.tree.getWeightsAt(idx);
    return this.findKthLargest(weights, k);
  }
}
```

