```javascript
class RollingWindow {
  constructor(n) {
    this.n = n;
    this.buf = new Array(n);
    this.head = 0; // points to oldest element
    this.size = 0;
    this.sum = 0;
    this.maxDQ = []; // decreasing values
  }
  push(v) {
    // evict oldest if full
    if (this.size === this.n) {
      const old = this.buf[this.head];
      this.sum -= old;
      if (this.maxDQ[0] === old) this.maxDQ.shift();
      this.head = (this.head + 1) % this.n;
      this.size--;
    }
    const idx = (this.head + this.size) % this.n;
    this.buf[idx] = v;
    this.size++;
    this.sum += v;
    while (this.maxDQ.length && this.maxDQ[this.maxDQ.length - 1] < v) this.maxDQ.pop();
    this.maxDQ.push(v);
  }
  sumWindow() {
    return this.sum;
  }
  maxWindow() {
    return this.maxDQ.length ? this.maxDQ[0] : undefined;
  }
}
```

