// Pseudocode sketch of augmentation during merge
function pull(node) {
  const L = node.left, R = node.right;
  const leftSize = L ? L.size : 0;
  const rightSize = R ? R.size : 0;
  node.size = 1 + leftSize + rightSize;
  const leftPref = L ? L.pref : 0;
  const rightPref = R ? R.pref : 0;
  const leftSuff = L ? L.suff : 0;
  const rightSuff = R ? R.suff : 0;
  const leftBest = L ? L.best : 0;
  const rightBest = R ? R.best : 0;
  node.pref = (L && L.pref === L.size) ? L.size + (R ? R.pref : 0) : leftPref;
  node.suff = (R && R.suff === R.size) ? R.size + (L ? L.suff : 0) : rightSuff;
  node.best = Math.max(leftBest, rightBest, (L ? L.suff : 0) + (R ? R.pref : 0));
}
```

