## Code Example
```javascript
class IntervalSet {
  constructor(coords) {
    this.tree = new SegmentTree(coords.length);
  }

  insertInterval(l, r, w, id) {
    this.tree.rangeUpdate(l, r, (node) => node.S.add([w, id]));
  }

  eraseInterval(id) {
    this.tree.rangeUpdate(l, r, (node) => node.S.delete(this.findPair(id)));
  }

  updateIntervalWeight(id, newW) {
    const oldPair = this.findPair(id);
    this.tree.rangeUpdate(oldPair.l, oldPair.r, (node) => {
      node.S.delete(oldPair);
      node.S.add([newW, id]);
    });
  }

  sumWeightsAtPoint(x) {
    return this.tree.pointQuery(x).reduce((sum, node) => 
      sum + node.S.sumWeights(), 0);
  }

  kthLargestWeightAtPoint(x, k) {
    let lo = 0, hi = MAX_WEIGHT;
    while (lo < hi) {
      const mid = Math.floor((lo + hi + 1) / 2);
      const cnt = this.countGreaterThan(x, mid);
      if (cnt >= k) lo = mid;
      else hi = mid - 1;
    }
    return lo;
  }
}
```

