class Fenwick {
  constructor(n){ this.n=n; this.f=new Array(n+2).fill(0); }
  add(i, delta){ for(; i<=this.n; i+=i&-i) this.f[i]+=delta; }
  sum(i){ let s=0; for(; i>0; i-=i&-i) s+=this.f[i]; return s; }
}
class IntervalCoverage {
  constructor(coords){ // coords: sorted unique endpoints and endpoints+1
    this.coords = coords;
    this.bit = new Fenwick(coords.length+2);
    this.cnt = new Map(); // key "l,r" -> count of such intervals
  }
  idx(v){ // 1-based index for v in coords (assumes v is present)
    let l=0, r=this.coords.length; while(l<r){ const m=(l+r)>>1; if(this.coords[m] >= v) r=m; else l=m+1; } return l+1;
  }
  addInterval(l,r){ const key=`${l},${r}`; this.cnt.set(key, (this.cnt.get(key)||0)+1);
    this.bit.add(this.idx(l), +1);
    this.bit.add(this.idx(r+1), -1);
  }
  removeInterval(l,r){ const key=`${l},${r}`; const c=(this.cnt.get(key)||0); if(c<=0) return; this.cnt.set(key, c-1);
    this.bit.add(this.idx(l), -1);
    this.bit.add(this.idx(r+1), +1);
  }
  queryCoverage(x){ return this.bit.sum(this.idx(x)); }
}
