class MedianMultiset {
  constructor(){ this.lower = new MaxHeap(); this.upper = new MinHeap(); this.delayed = new Map(); this.size = 0; }
  _pruneLower(){ while(!this.lower.isEmpty() && (this.delayed.get(this.lower.peek())||0)>0){ const v=this.lower.pop(); this.delayed.set(v,(this.delayed.get(v)||0)-1); } }
  _pruneUpper(){ while(!this.upper.isEmpty() && (this.delayed.get(this.upper.peek())||0)>0){ const v=this.upper.pop(); this.delayed.set(v,(this.delayed.get(v)||0)-1); } }
  _balance(){ if(this.lower.size>this.upper.size+1) this.upper.push(this.lower.pop()); else if(this.upper.size>this.lower.size) this.lower.push(this.upper.pop()); }
  insert(v){ if(this.lower.isEmpty()||v<=this.lower.peek()) this.lower.push(v); else this.upper.push(v); this.size++; this._balance(); }
  erase(v){ if(this.size===0) return; this.delayed.set(v,(this.delayed.get(v)||0)+1); this.size--; if(v<=this.lower.peek()) this._pruneLower(); else this._pruneUpper(); this._balance(); }
  getMedian(){ if(this.size===0) return null; this._pruneLower(); this._pruneUpper(); if(this.size%2===1) return this.lower.peek(); return (this.lower.peek()+this.upper.peek())/2; }
}
