- **Per-block sums**: Enable O(1) block-level aggregation during rangeSum operations
- **Amortized balance**: Split/merge operations maintain block sizes within bounds, ensuring O(√n) amortized time per update
- **Edge-case handling**: Proper merge/split logic prevents pathological degradation

## Code Example
```javascript
class SqrtArray {
  constructor() {
    this.blocks = [];
    this.B = 2;
  }

  _getBlock(index) {
    let count = 0;
    for (const block of this.blocks) {
      if (index < count + block.length) return block;
      count += block.length;
    }
    throw new Error('Index out of bounds');
  }

  insertAt(index, value) {
    const block = this._getBlock(index);
    block.push(value);
    block.sum += value;
    if (block.length > 2 * this.B) this._split(block);
  }

  eraseAt(index) {
    const block = this._getBlock(index);
    block.splice(index, 1);
    block.sum -= value;
    if (block.length < this.B / 2) this._merge(block);
  }

  rangeSum(l, r) {
    let sum = 0;
    let count = 0;
    for (const block of this.blocks) {
      const blockStart = count;
      const blockEnd = count + block.length - 1;
      if (r < blockStart || l > blockEnd) { count += block.length; continue; }
      const start = Math.max(l, blockStart);
      const end = Math.min(r, blockEnd);
      if (start === blockStart && end === blockEnd) sum += block.sum;
      else for (let i = start; i <= end; i++) sum += block[i];
      count += block.length;
    }
    return sum;
  }

  _split(block) {
    const mid = Math.floor(block.length / 2);
    const newBlock = { arr: block.arr.splice(mid), sum: newBlock.arr.reduce((a,b)=>a+b,0) };
    block.sum = block.arr.reduce((a,b)=>a+b,0);
    const idx = this.blocks.indexOf(block);
    this.blocks.splice(idx + 1, 0, newBlock);
  }

  _merge(block) {
    const idx = this.blocks.indexOf(block);
    const neighbor = idx > 0 ? this.blocks[idx - 1] : this.blocks[idx + 1];
    const [small, big] = neighbor.length > block.length ? [block, neighbor] : [neighbor, block];
    big.arr.push(...small.arr);
    big.sum += small.sum;
    this.blocks.splice(this.blocks.indexOf(small), 1);
  }
}
```

