We implement an implicit treap where each node stores: ch (the character), sz (subtree size), hash (subtree polynomial hash), priority (random heap key), and left/right pointers. The size tracks subtree node count; the hash is computed as:

`hash = hash(left) * p^(1+sz(right)) + code(ch) * p^(sz(right)) + hash(right)`

The implicit key is the cumulative size of the left subtree. Split and merge operations isolate subtrees by position: `split(root, k)` separates into (L, R) where L contains the first k nodes, while `merge(L, R)` combines two treaps preserving heap order by priority and BST order by implicit position. To compute `getHash(l, r)`, we split at position r to isolate the right portion, split again at l-1 to isolate the target substring, extract its hash, then merge everything back. Precompute p^i modulo M up to max n, and use double hashing (two independent moduli) to minimize collision probability.

```javascript
class Node {
  constructor(ch) {
    this.ch = ch;
    this.pri = Math.random();
    this.l = this.r = null;
    this.sz = 1;
    this.hash = ch.charCodeAt(0);
  }
}

function sz(n) { return n ? n.sz : 0; }
function h(n) { return n ? n.hash : 0; }

function upd(n) {
  if (!n) return;
  n.sz = 1 + sz(n.l) + sz(n.r);
  n.hash = (h(n.l) * P.pow(sz(n.r) + 1) + 
            n.ch.charCodeAt(0) * P.pow(sz(n.r)) + 
            h(n.r)) % MOD;
}

function push(n) { /* propagate lazy flags if needed */ }

function split(n, k) {
  if (!n) return [null, null];
  push(n);
  if (sz(n.l) >= k) {
    const [l, r] = split(n.l, k);
    n.l = r;
    upd(n);
    return [l, n];
  } else {
    const [l, r] = split(n.r, k - sz(n.l) - 1);
    n.r = l;
    upd(n);
    return [n, r];
  }
}

function merge(a, b) {
  if (!a || !b) return a || b;
  if (a.pri > b.pri) {
    push(a);
    a.r = merge(a.r, b);
    upd(a);
    return a;
  } else {
    push(b);
    b.l = merge(a, b.l);
    upd(b);
    return b;
  }
}
```

