```javascript
class Node {
  constructor(key) {
    this.key = key;
    this.dup = 1;
    this.left = null;
    this.right = null;
  }

  get size() {
    return this.dup + (this.left?.size ?? 0) + (this.right?.size ?? 0);
  }
}

class Treap {
  constructor() {
    this.root = null;
  }

  insert(key) {
    this.root = this._insert(this.root, key);
  }

  _insert(node, key) {
    if (!node) return new Node(key);
    if (key === node.key) {
      node.dup++;
    } else if (key < node.key) {
      node.left = this._insert(node.left, key);
    } else {
      node.right = this._insert(node.right, key);
    }
    return node;
  }

  erase(key) {
    this.root = this._erase(this.root, key);
  }

  _erase(node, key) {
    if (!node) return null;
    if (key === node.key) {
      node.dup--;
      if (node.dup === 0) return this._merge(node.left, node.right);
    } else if (key < node.key) {
      node.left = this._erase(node.left, key);
    } else {
      node.right = this._erase(node.right, key);
    }
    return node;
  }

  _merge(left, right) {
    if (!left || !right) return left ?? right;
    // Simplified: in a real Treap, merge by priority
    return this._bstMerge(left, right);
  }

  _bstMerge(left, right) {
    if (!left) return right;
    if (!right) return left;
    const node = left;
    node.right = this._bstMerge(node.right, right);
    return node;
  }

  getRank(v) {
    return this._getRank(this.root, v);
  }

  _getRank(node, v) {
    if (!node) return 0;
    if (v < node.key) {
      return this._getRank(node.left, v);
    }
    const leftSize = node.left?.size ?? 0;
    return leftSize + node.dup + this._getRank(node.right, v);
  }
}
```

