## Code Example
```javascript
class Node {
  constructor(val, prio, left = null, right = null) {
    this.val = val;
    this.prio = prio;
    this.left = left;
    this.right = right;
    this.size = 1;
    this.sum = val;
  }

  update() {
    this.size = 1 + (this.left?.size ?? 0) + (this.right?.size ?? 0);
    this.sum = this.val + (this.left?.sum ?? 0) + (this.right?.sum ?? 0);
  }
}

function split(root, k) {
  if (!root) return [null, null];
  const leftSize = root.left?.size ?? 0;
  if (k <= leftSize) {
    const [l, r] = split(root.left, k);
    root.left = r;
    root.update();
    return [l, root];
  } else {
    const [l, r] = split(root.right, k - leftSize - 1);
    root.right = l;
    root.update();
    return [root, r];
  }
}

function merge(left, right) {
  if (!left || !right) return left ?? right;
  if (left.prio < right.prio) {
    left.right = merge(left.right, right);
    left.update();
    return left;
  } else {
    right.left = merge(left, right.left);
    right.update();
    return right;
  }
}

function rangeSum(root, l, r) {
  const [, mid] = split(root, l);
  const [target, rest] = split(mid, r - l + 1);
  const result = target?.sum ?? 0;
  return merge(merge(null, target), rest);
}

function insertAt(root, index, val) {
  const [left, right] = split(root, index);
  const newNode = new Node(val, Math.random());
  return merge(merge(left, newNode), right);
}

function eraseAt(root, index) {
  const [left, mid] = split(root, index);
  const [, right] = split(mid, 1);
  return merge(left, right);
}
```

