class Fenwick {
  constructor(n) {
    this.n = n;
    this.f = new Array(n + 1).fill(0);
  }
  add(i, delta) {
    for (; i <= this.n; i += i & -i) this.f[i] += delta;
  }
  sum(i) {
    let s = 0;
    for (; i > 0; i -= i & -i) s += this.f[i];
    return s;
  }
  kth(k) {
    let idx = 0;
    let bit = 1;
    while ((bit << 1) <= this.n) bit <<= 1;
    for (let d = bit; d > 0; d >>= 1) {
      const next = idx + d;
      if (next <= this.n && this.f[next] < k) {
        idx = next;
        k -= this.f[next];
      }
    }
    return idx + 1;
  }
}
