## Code Example
```javascript
class TrieNode {
  constructor() {
    this.children = new Map();
    this.pass = 0;
    this.end = 0;
  }
}
class TrieDict {
  constructor() { this.root = new TrieNode(); }
  insert(word) {
    let p = this.root; p.pass++;
    for (const ch of word) {
      if (!p.children.has(ch)) p.children.set(ch, new TrieNode());
      p = p.children.get(ch); p.pass++;
    }
    p.end++;
  }
  erase(word) {
    if (!this._exists(word)) return;
    let p = this.root; p.pass--;
    for (const ch of word) {
      const nxt = p.children.get(ch); nxt.pass--;
      if (nxt.pass === 0) p.children.delete(ch); else p = nxt;
    }
    p.end--;
  }
  countWithPrefix(prefix) {
    const node = this._getNode(prefix); return node ? node.pass : 0;
  }
  kthWordWithPrefix(prefix, k) {
    const node = this._getNode(prefix); if (!node) return null;
    let res = prefix; let cur = node;
    // If k falls on words exactly equal to prefix
    if (cur.end >= k) return res;
    k -= cur.end;
    while (true) {
      const keys = Array.from(cur.children.keys()).sort();
      for (const c of keys) {
        const child = cur.children.get(c);
        if (child.pass >= k) { res += c; cur = child; if (cur.end >= k) return res; k -= cur.end; break; }
        k -= child.pass;
      } else { return null; }
    }
  }
  _getNode(s) {
    let p = this.root; for (const ch of s) { if (!p.children.has(ch)) return null; p = p.children.get(ch); } return p;
  }
  _exists(word) { const n = this._getNode(word); return !!n && n.end > 0; }
}
```

