## Why This Is Asked
Tests the ability to design a dynamic string structure supporting weighted, prefix-based queries and order-statistics. A Trie augmented with per-node aggregates enables efficient prefix sums and k-th retrieval while handling duplicates via cumulative weights.

## Key Concepts
- Trie with per-node aggregates (subtreeWeight, terminalWeight)
- O(len(word)) time complexity for insert/erase operations
- O(len(prefix)) for prefix-sum queries
- O(len(prefix) + len(target_word)) for k-th word queries
- Duplicate handling via cumulative weight values

## Code Example
```javascript
class WeightedTrie {
  constructor() {
    this.root = this.createNode();
  }

  createNode() {
    return {
      children: new Array(26).fill(null),
      subtreeWeight: 0,
      terminalWeight: 0,
    };
  }

  charIndex(c) {
    return c.charCodeAt(0) - 'a'.charCodeAt(0);
  }

  insertWord(word, w) {
    let node = this.root;
    for (const c of word) {
      const i = this.charIndex(c);
      if (!node.children[i]) {
        node.children[i] = this.createNode();
      }
      node = node.children[i];
      node.subtreeWeight += w;
    }
    node.terminalWeight += w;
  }

  eraseWord(word, w) {
    let node = this.root;
    for (const c of word) {
      const i = this.charIndex(c);
      node = node.children[i];
      node.subtreeWeight -= w;
    }
    node.terminalWeight -= w;
  }

  queryPrefixSum(prefix) {
    let node = this.root;
    for (const c of prefix) {
      const i = this.charIndex(c);
      if (!node.children[i]) return 0;
      node = node.children[i];
    }
    return node.subtreeWeight;
  }

  kthWordWithPrefix(prefix, k) {
    let node = this.root;
    for (const c of prefix) {
      const i = this.charIndex(c);
      if (!node.children[i]) return null;
      node = node.children[i];
    }
    if (k > node.subtreeWeight) return null;
    let result = prefix;
    while (!node.terminalWeight || k > node.terminalWeight) {
      k -= node.terminalWeight;
      for (let i = 0; i < 26; i++) {
        if (node.children[i] && node.children[i].subtreeWeight >= k) {
          result += String.fromCharCode('a'.charCodeAt(0) + i);
          node = node.children[i];
          break;
        }
        k -= node.children[i]?.subtreeWeight || 0;
      }
    }
    return result;
  }
}
