class MedianStream {
  constructor() {
    this.low = new MaxHeap();  // Lower half
    this.high = new MinHeap(); // Upper half
  }

  insert(x) {
    // Insert into appropriate heap and rebalance
    if (this.low.isEmpty() || x <= this.low.peek()) {
      this.low.push(x);
    } else {
      this.high.push(x);
    }

    // Rebalance to maintain size difference ≤ 1
    if (this.low.size() > this.high.size() + 1) {
      this.high.push(this.low.pop());
    } else if (this.high.size() > this.low.size() + 1) {
      this.low.push(this.high.pop());
    }
  }

  getMedian() {
    if (this.low.size() > this.high.size()) {
      return this.low.peek();
    } else if (this.high.size() > this.low.size()) {
      return this.high.peek();
    } else {
      return (this.low.peek() + this.high.peek()) / 2;
    }
  }
}
