class MaxQueue {
  constructor() {
    this.in = [];
    this.out = [];
    this.total = 0;
  }
  push(x) {
    const newMax = this.in.length === 0 ? x : Math.max(x, this.in[this.in.length - 1].max);
    this.in.push({ val: x, max: newMax });
    this.total += x;
  }
  pop() {
    if (this.out.length === 0) {
      while (this.in.length > 0) {
        const v = this.in.pop().val;
        const newMax = this.out.length === 0 ? v : Math.max(v, this.out[this.out.length - 1].max);
        this.out.push({ val: v, max: newMax });
      }
    }
    if (this.out.length === 0) return undefined;
    const popped = this.out.pop();
    this.total -= popped.val;
    return popped.val;
  }
  max() {
    const maxIn = this.in.length === 0 ? -Infinity : this.in[this.in.length - 1].max;
    const maxOut = this.out.length === 0 ? -Infinity : this.out[this.out.length - 1].max;
    if (maxIn === -Infinity && maxOut === -Infinity) return undefined;
    return Math.max(maxIn, maxOut);
  }
  sum() {
    return this.total;
  }
}
