class MinMaxDeque {
  constructor() {
    this.front = [];
    this.back = [];
  }
  pushFront(x) {
    const last = this.front[this.front.length - 1];
    const mn = last ? Math.min(x, last.min) : x;
    const mx = last ? Math.max(x, last.max) : x;
    this.front.push({ v: x, min: mn, max: mx });
  }
  pushBack(x) {
    const last = this.back[this.back.length - 1];
    const mn = last ? Math.min(x, last.min) : x;
    const mx = last ? Math.max(x, last.max) : x;
    this.back.push({ v: x, min: mn, max: mx });
  }
  popFront() {
    if (this.front.length === 0) {
      while (this.back.length) this.pushFront(this.back.pop().v);
    }
    if (this.front.length === 0) throw new Error('empty');
    return this.front.pop().v;
  }
  popBack() {
    if (this.back.length === 0) {
      while (this.front.length) this.pushBack(this.front.pop().v);
    }
    if (this.back.length === 0) throw new Error('empty');
    return this.back.pop().v;
  }
  getMin() {
    if (this.front.length === 0 && this.back.length === 0) throw new Error('empty');
    let mn = null;
    if (this.front.length) mn = this.front[this.front.length - 1].min;
    if (this.back.length) {
      const bmin = this.back[this.back.length - 1].min;
      mn = mn === null ? bmin : Math.min(mn, bmin);
    }
    return mn;
  }
  getMax() {
    if (this.front.length === 0 && this.back.length === 0) throw new Error('empty');
    let mx = null;
    if (this.front.length) mx = this.front[this.front.length - 1].max;
    if (this.back.length) {
      const bmax = this.back[this.back.length - 1].max;
      mx = mx === null ? bmax : Math.max(mx, bmax);
    }
    return mx;
  }
}
