class RollbackDSU {
  constructor(n){
    this.parent = Array.from({length:n}, (_,i)=>i);
    this.sz = Array(n).fill(1);
    this.ch = [];
  }
  find(x){ while (this.parent[x]!==x) x = this.parent[x]; return x; }
  union(a,b){
    a = this.find(a); b = this.find(b);
    if (a===b){ this.ch.push(null); return; }
    if (this.sz[a] < this.sz[b]) [a,b] = [b,a];
    this.ch.push([b, this.parent[b], a, this.sz[a]]);
    this.parent[b] = a; this.sz[a] += this.sz[b];
  }
  snapshot(){ return this.ch.length; }
  rollback(snap){
    while (this.ch.length > snap){
      const ch = this.ch.pop();
      if (!ch) continue;
      const [b, oldP, a, oldS] = ch;
      this.parent[b] = oldP; this.sz[a] = oldS;
