class WindowCounter {
  constructor(W) {
    this.W = W;
    this.count = new Map(); // user -> cnt
    this.buckets = new Map(); // cnt -> Set<user>
    this.events = new Deque(); // (ts, user)
  }
  _addToBucket(cnt, user) {
    if (!this.buckets.has(cnt)) this.buckets.set(cnt, new Set());
    this.buckets.get(cnt).add(user);
  }
  _removeFromBucket(cnt, user) {
    if (!this.buckets.has(cnt)) return;
    this.buckets.get(cnt).delete(user);
    if (this.buckets.get(cnt).size === 0) this.buckets.delete(cnt);
  }
  prune(now) {
    while (this.events.length && this.events.peek().ts <= now - this.W) {
      const {ts, user} = this.events.shift();
      const c = this.count.get(user) || 0;
      if (c > 0) {
        this._removeFromBucket(c, user);
        const nc = c - 1;
        if (nc > 0) {
          this._addToBucket(nc, user);
          this.count.set(user, nc);
        } else {
          this.count.delete(user);
        }
      }
    }
  }
  addEvent(user, ts) {
    this.events.push({ts, user});
    this.prune(ts);
    const c = this.count.get(user) || 0;
    if (c > 0) this._removeFromBucket(c, user);
    const nc = c + 1;
    this._addToBucket(nc, user);
    this.count.set(user, nc);
  }
  topK(now, k) {
    const res = [];
    // iterate counts from high to low
    const counts = Array.from(this.buckets.keys()).sort((a,b)=>b-a);
    for (const cnt of counts) {
      const set = this.buckets.get(cnt);
      const users = Array.from(set).sort((a,b)=>a-b); // tie-breaker by userId
      for (const u of users) {
        res.push([u, cnt]);
        if (res.length === k) return res;
      }
    }
    return res;
  }
}
```

