    this.treap.insert(node);
    this.idMap.set(id, node);
  }

  updateScore(id, newScore) {
    const node = this.idMap.get(id);
    if (node) {
      this.insertItem(id, newScore, node.expiry);
    }
  }

  removeItem(id) {
    const node = this.idMap.get(id);
    if (node) {
      this.treap.remove(node);
      this.idMap.delete(id);
    }
  }

  queryTopK(now, k) {
    const result = [];
    const iterator = this.treap.inOrder();
    for (const node of iterator) {
      if (result.length >= k) break;
      if (node.expiry > now) {
        result.push({id: node.id, score: node.score});
      }
    }
    return result;
  }
}
