class WeightedIntervalTree {
  constructor(minCoord, maxCoord) {
    this.root = this.build(minCoord, maxCoord);
  }

  build(l, r) {
    return {
      left: l, right: r,
      weights: new Map(), // weight -> count
      leftChild: null, rightChild: null
    };
  }

  update(node, l, r, w, delta) {
    if (node.left > r || node.right < l) return;
    if (l <= node.left && node.right <= r) {
      const count = node.weights.get(w) || 0;
      node.weights.set(w, count + delta);
      if (count + delta === 0) node.weights.delete(w);
    } else {
      if (!node.leftChild) {
        const mid = Math.floor((node.left + node.right) / 2);
        node.leftChild = this.build(node.left, mid);
        node.rightChild = this.build(mid + 1, node.right);
      }
      this.update(node.leftChild, l, r, w, delta);
      this.update(node.rightChild, l, r, w, delta);
    }
  }

  insertInterval(l, r, w) {
    this.update(this.root, l, r, w, 1);
  }

  eraseInterval(l, r, w) {
    this.update(this.root, l, r, w, -1);
  }

  sumWeightAtPoint(p, node = this.root) {
    if (!node || node.left > p || node.right < p) return 0;
    let sum = 0;
    for (const [w, count] of node.weights) {
      sum += w * count;
    }
    if (node.leftChild) {
      sum += this.sumWeightAtPoint(p, node.leftChild);
      sum += this.sumWeightAtPoint(p, node.rightChild);
    }
    return sum;
  }

  kthLargestWeightAtPoint(p, k) {
    // Collect all weights at point p
    const weights = [];
    this.collectWeights(this.root, p, weights);

    // Sort descending and find k-th largest
    weights.sort((a, b) => b - a);
    return weights[k - 1] || null;
  }

  collectWeights(node, p, weights) {
    if (!node || node.left > p || node.right < p) return;

    for (const [w, count] of node.weights) {
      for (let i = 0; i < count; i++) {
        weights.push(w);
      }
    }

    if (node.leftChild) {
      this.collectWeights(node.leftChild, p, weights);
      this.collectWeights(node.rightChild, p, weights);
    }
  }
}
```

