## Code Example
```javascript
class WordFreqDS {
  constructor() {
    this.counts = new Map();
    this.buckets = new Map(); // freq -> Set<string>
  }
  _ensureBucket(freq) {
    if (!this.buckets.has(freq)) this.buckets.set(freq, new Set());
  }
  addWord(word) {
    const prev = this.counts.get(word) || 0;
    if (prev > 0) this.buckets.get(prev).delete(word);
    const next = prev + 1;
    this.counts.set(word, next);
    this._ensureBucket(next);
    this.buckets.get(next).add(word);
  }
  eraseWord(word) {
    const prev = this.counts.get(word);
    if (!prev) return;
    this.buckets.get(prev).delete(word);
    const next = prev - 1;
    if (next === 0) {
      this.counts.delete(word);
      return;
    }
    this.counts.set(word, next);
    this._ensureBucket(next);
    this.buckets.get(next).add(word);
  }
  getFrequency(word) {
    return this.counts.get(word) || 0;
  }
  topKWords(n) {
    const freqs = Array.from(this.buckets.keys()).sort((a,b)=>b-a);
    const res = [];
    for (const freq of freqs) {
      const words = Array.from(this.buckets.get(freq)).sort();
      for (const w of words) {
        res.push(w);
        if (res.length === n) return res;
      }
    }
    return res;
  }
}
```

