class MaxHeap {
  constructor(){ this.a=[]; }
  size(){ return this.a.length; }
  push(x){ this.a.push(x); this.bubbleUp(this.a.length-1); }
  peek(){ return this.a[0]; }
  pop(){ if(!this.a.length) return null; const top=this.a[0]; const end=this.a.pop(); if(this.a.length){ this.a[0]=end; this.bubbleDown(0); } return top; }
  bubbleUp(i){ while(i>0){ const p=(i-1)>>1; if(this.a[p].count>=this.a[i].count) break; [this.a[p], this.a[i]]=[this.a[i], this.a[p]]; i=p; } }
  bubbleDown(i){ const n=this.a.length; while(true){ let l=i*2+1, r=l+1, largest=i; if(l<n && this.a[l].count>this.a[largest].count) largest=l; if(r<n && this.a[r].count>this.a[largest].count) largest=r; if(largest===i) break; [this.a[i], this.a[largest]]=[this.a[largest], this.a[i]]; i=largest; } }
}
class FrequencyDS {
  constructor(){ this.counts=new Map(); this.heap=new MaxHeap(); }
  insert(s){ const c=(this.counts.get(s)||0)+1; this.counts.set(s,c); this.heap.push({count:c, s}); }
  erase(s, cnt=1){ const old=this.counts.get(s)||0; const nc=Math.max(0, old-cnt); if(nc>0) this.counts.set(s,nc); else this.counts.delete(s); if(nc>0) this.heap.push({count:nc, s}); }
  countOf(s){ return this.counts.get(s)||0; }
  getMostFrequent(){ while(this.heap.size()){ const top=this.heap.peek(); const cur=this.counts.get(top.s)||0; if(cur!==top.count){ this.heap.pop(); continue; } return top.s; } return null; }
}
