- Time: O(log m) per operation, m distinct values

## Code Example

```javascript
class Fenwick {
  constructor(n){ this.n=n; this.f=new Array(n+1).fill(0); }
  add(i, delta){ for(; i<=this.n; i+= i&-i) this.f[i]+=delta; }
  sum(i){ let s=0; for(; i>0; i-= i&-i) s+=this.f[i]; return s; }
  kth(k){
    let idx=0; let bit=1;
    while((bit<<1) <= this.n) bit <<= 1;
    for(let step=bit; step>0; step>>=1){
      const t = idx+step;
      if(t<=this.n && this.f[t] < k){
        idx = t;
        k -= this.f[t];
      }
    }
    return idx+1;
  }
}
class KthMultiset {
  constructor(vals){
    this.values = Array.from(new Set(vals)).sort((a,b)=>a-b);
    this.index = new Map(this.values.map((v,i)=>[v,i+1]));
    this.ft = new Fenwick(this.values.length);
  }
  add(x){ const i = this.index.get(x); if(i) this.ft.add(i, 1); }
  remove(x){ const i = this.index.get(x); if(i) this.ft.add(i, -1); }
  getKthSmallest(k){ const idx = this.ft.kth(k); return this.values[idx-1]; }
}
```

