class SlidingWindowMax {
  constructor(K) {
    this.K = K;
    this.dq = []; // stores indices
    this.values = [];
    this.i = 0;
  }
  push(x) {
    this.values[this.i] = x;
    while (this.dq.length && this.values[this.dq[this.dq.length - 1]] <= x) {
      this.dq.pop();
    }
    this.dq.push(this.i);
    if (this.dq[0] <= this.i - this.K) {
      this.dq.shift();
    }
    this.i++;
  }
  getMax() {
    return this.dq.length ? this.values[this.dq[0]] : null;
  }
  size() {
    return Math.min(this.i, this.K);
  }
}
