## Code Example
```javascript
class TrieNode {
  constructor() {
    this.children = new Map();
    this.pass = 0;
    this.end = 0;
  }
}

class WordDict {
  constructor() { this.root = new TrieNode(); }
  insert(word) {
    let node = this.root;
    node.pass++;
    for (const ch of word) {
      if (!node.children.has(ch)) node.children.set(ch, new TrieNode());
      node = node.children.get(ch);
      node.pass++;
    }
    node.end++;
  }
  delete(word) {
    if (!this._exists(word)) return false;
    let node = this.root;
    node.pass--;
    for (const ch of word) {
      const next = node.children.get(ch);
      next.pass--;
      if (next.pass === 0) { node.children.delete(ch); return true; }
      node = next;
    }
    node.end--;
    return true;
  }
  countPrefix(prefix) {
    let node = this.root;
    for (const ch of prefix) {
      if (!node.children.has(ch)) return 0;
      node = node.children.get(ch);
    }
    return node.pass;
  }
  _exists(word) {
    let node = this.root;
    for (const ch of word) {
      if (!node.children.has(ch)) return false;
      node = node.children.get(ch);
    }
    return node.end > 0;
  }
}
```

